// Build the transcript envelope + look up the per-client analysis URL.
const ev = $('Is Closed?').first().json;        // original state event
const conv = $('Fetch Conversation').first().json; // conversation resource
const msgs = $json.messages || [];                 // from Fetch Transcript

// Parse client_id from FriendlyName: chat_{clientId}_user_..._{ts}
const fn = conv.friendly_name || '';
const afterChat = fn.startsWith('chat_') ? fn.slice(5) : fn;
let clientId = 'digishares';
if (afterChat.includes('_user_')) {
  const before = afterChat.split('_user_')[0];
  if (before) clientId = before;
}

// Empty conversation -> nothing to analyse, drop.
if (msgs.length === 0) return [];

// ── Per-client analysis routing (mirror of Message Handler ROUTING) ──
// Empty webhookUrl = no postpro brain yet -> skip.
const ANALYSIS_ROUTING = {
  digishares: { webhookUrl: '' },
  alkoholcz:  { webhookUrl: '' },
  pompo:      { webhookUrl: '' },
  atlaschat:  { webhookUrl: '' },
  ladenta:    { webhookUrl: '' },
};
const route = ANALYSIS_ROUTING[clientId];
const analysisWebhookUrl = (route && route.webhookUrl) ? route.webhookUrl : '';

const CZ = ['alkoholcz', 'pompo', 'ladenta'];
const payload = {
  conversation_sid: ev.ConversationSid,
  client_id: clientId,
  reason: ev.Reason || '',
  state_from: ev.StateFrom || '',
  locale: CZ.includes(clientId) ? 'cs' : 'en',
  started_at: conv.date_created || '',
  ended_at: ev.StateUpdated || '',
  message_count: msgs.length,
  transcript: msgs.map(m => ({ author: m.author, body: m.body, timestamp: m.date_created })),
};

return [{ json: { ...payload, analysisWebhookUrl, routing_status: analysisWebhookUrl ? 'routed' : 'skipped_no_url' } }];
